   125→FN_INTERNAL int upload_firmware(fnusb_dev* dev, char * filename) {
   126→    freenect_context* ctx = dev->parent->parent;
   127→	/* Search for firmware file (audios.bin) in the following places:
   128→	 * $LIBFREENECT_FIRMWARE_PATH
   129→	 * .
   130→	 * ${HOME}/.libfreenect
   131→	 * /usr/local/share/libfreenect
   132→	 * /usr/share/libfreenect
   133→     * ./../Resources/ ( for OS X )
   134→	 */
   135→    
   136→    //need to add a forward slash
   137→    char fw_filename[1024];
   138→    sprintf(fw_filename, "/%s", filename);
   139→    
   140→    int filenamelen = strlen(fw_filename);
   141→	int i;
   142→	int searchpathcount;
   143→	FILE* fw = NULL;
   144→    
   145→	for(i = 0, searchpathcount = 6; !fw && i < searchpathcount; i++) {
   146→		char* fwfile;
   147→		int needs_free = 0;
   148→		switch(i) {
   149→			case 0: {
   150→				char* envpath = getenv("LIBFREENECT_FIRMWARE_PATH");
   151→				if (!envpath)
   152→					continue;
   153→				int pathlen = strlen(envpath);
   154→				fwfile = (char *)malloc(pathlen + filenamelen + 1);
   155→				strcpy(fwfile, envpath);
   156→				strcat(fwfile, fw_filename);
   157→				needs_free = 1;
   158→				}
   159→				break;
   160→			case 1:
   161→				//fwfile = "./audios.bin";
   162→				fwfile = (char *)malloc(2048);
   163→                needs_free = 1;
   164→                sprintf(fwfile, ".%s", fw_filename);
   165→				break;
   166→			case 2: {
   167→				// Construct $HOME/.libfreenect/
   168→				char* home = getenv("HOME");
   169→				if (!home)
   170→					continue;
   171→				int homelen = strlen(home);
   172→				char* dotfolder = "/.libfreenect";
   173→				int locallen = strlen(dotfolder);
   174→				fwfile = (char*)malloc(homelen + locallen + filenamelen + 1);
   175→				strcpy(fwfile, home);
   176→				strcat(fwfile, dotfolder);
   177→				strcat(fwfile, fw_filename);
   178→				needs_free = 1;
   179→				}
   180→				break;
   181→			case 3:
   182→				//fwfile = "/usr/local/share/libfreenect/audios.bin";
   183→                fwfile = (char *)malloc(2048);
   184→                needs_free = 1;
   185→                sprintf(fwfile, "/usr/local/share/libfreenect%s", fw_filename);
   186→				break;
   187→			case 4:
   188→				//fwfile = "/usr/share/libfreenect/audios.bin";
   189→				fwfile = (char *)malloc(2048);
   190→                needs_free = 1;
   191→                sprintf(fwfile, "/usr/share/libfreenect%s", fw_filename);
   192→				break;
   193→			case 5:
   194→                //fwfile = "./../Resources/audios.bin"; //default for OS X equivilant to: "./audios.bin";
   195→				fwfile = (char *)malloc(2048);
   196→                needs_free = 1;
   197→                sprintf(fwfile, "./../Resources%s", fw_filename);
   198→				break;
   199→			default: break;
   200→		}
   201→		FN_INFO("Trying to open %s as firmware...\n", fwfile);
   202→		fw = fopen(fwfile, "rb");
   203→		if (needs_free) {
   204→			free(fwfile);
   205→		}
   206→	}
   207→	if (!fw) {
   208→		FN_ERROR("upload_firmware: failed to find firmware file.\n");
   209→		return -errno;
   210→	}
   211→    
   212→    // get the number of bytes of the file
   213→    fseek(fw , 0, SEEK_END);
   214→    int fw_num_bytes = ftell(fw);
   215→    rewind(fw);
   216→    
   217→    if( fw_num_bytes <= 0 ){
   218→		FN_ERROR("upload_firmware: failed to find file with any data.\n");
   219→		return -errno;
   220→    }
   221→    
   222→    unsigned char * fw_bytes = (unsigned char *)malloc(fw_num_bytes);
   223→    int numRead = fread(fw_bytes, 1, fw_num_bytes, fw);
   224→    fw_num_bytes = numRead; // just in case
   225→
   226→    int retVal = upload_firmware_from_memory(dev, fw_bytes, fw_num_bytes);
   227→    
   228→    fclose(fw);
   229→    fw = NULL;
   230→    
   231→    return retVal;
   232→}
