   341→FN_INTERNAL int upload_cemd_data(fnusb_dev* dev) {
   342→	// Now we upload the CEMD data.
   343→	freenect_context* ctx = dev->parent->parent;
   344→	cemdloader_command cemdcmd;
   345→	memset(&cemdcmd, 0, sizeof(cemdcmd));
   346→	cemdcmd.magic = fn_le32(0x06022009);
   347→	cemdcmd.tag   = fn_le32(dev->parent->audio_tag);
   348→	cemdcmd.arg1  = fn_le32(0);
   349→	cemdcmd.cmd   = fn_le32(0x00000133);
   350→	cemdcmd.arg2  = fn_le32(0x00064014); // This is the length of the CEMD data.
   351→	FN_INFO("Starting CEMD data upload:\n");
   352→	int res;
   353→	int transferred;
   354→	res = fnusb_bulk(dev, 1, (unsigned char*)&cemdcmd, sizeof(cemdcmd), &transferred);
   355→	if(res != 0 || transferred != sizeof(cemdcmd)) {
   356→		FN_ERROR("Error: res: %d\ttransferred: %d (expected %d)\n", res, transferred, (int)sizeof(cemdcmd));
   357→		return -1;
   358→	}
   359→	res = get_reply(dev);
   360→	dev->parent->audio_tag++;
   361→
   362→	const char* cemd_filename = "cemd_data.bin";
   363→	FILE* cf = fopen(cemd_filename, "r");
   364→	if(cf == NULL) {
   365→		FN_ERROR("upload_cemd_data: Failed to open %s: error %d", cemd_filename, errno);
   366→		return errno;
   367→	}
   368→	uint32_t addr = 0x00000000;
   369→	int read = 0;
   370→	unsigned char page[0x4000];
   371→	do {
   372→		read = fread(page, 1, 0x4000, cf);
   373→		if(read <= 0) {
   374→			break;
   375→		}
   376→		//LOG("");
   377→		cemdcmd.tag  = fn_le32(dev->parent->audio_tag);
   378→		cemdcmd.arg1 = fn_le32(read);
   379→		cemdcmd.cmd  = fn_le32(0x134);
   380→		cemdcmd.arg2 = fn_le32(addr);
   381→		FN_INFO("About to send: ");
   382→		dump_cemd_cmd(ctx, cemdcmd);
   383→		// Send it off!
   384→		res = fnusb_bulk(dev, 1, (unsigned char*)&cemdcmd, sizeof(cemdcmd), &transferred);
   385→		if(res != 0 || transferred != sizeof(cemdcmd)) {
   386→			FN_ERROR("Error: res: %d\ttransferred: %d (expected %d)\n",res, transferred, (int)sizeof(cemdcmd));
   387→			return -1;
   388→		}
   389→		int bytes_sent = 0;
   390→		while(bytes_sent < read) {
   391→			int to_send = (read - bytes_sent > 512 ? 512 : read - bytes_sent);
   392→			res = fnusb_bulk(dev, 1, &page[bytes_sent], to_send, &transferred);
   393→			if(res != 0 || transferred != to_send) {
   394→				FN_ERROR("Error: res: %d\ttransferred: %d (expected %d)\n",res, transferred, to_send);
   395→				return -1;
   396→			}
   397→			bytes_sent += to_send;
   398→		}
   399→		res = get_reply(dev);
   400→		addr += (uint32_t)read;
   401→		dev->parent->audio_tag++;
   402→	} while (read > 0);
   403→	fclose(cf);
   404→	cf = NULL;
   405→
   406→	cemdcmd.tag  = fn_le32(dev->parent->audio_tag);
   407→	cemdcmd.arg1 = fn_le32(0); // bytes = 0
   408→	cemdcmd.cmd  = fn_le32(0x135);
   409→	cemdcmd.arg2 = fn_le32(0x00064000); // mimicing the USB logs.  This is the # of bytes of actual CEMD data after the 20-byte CEMD header.
   410→	FN_INFO("Finishing CEMD data upload...\n");
   411→	res = fnusb_bulk(dev, 1, (unsigned char*)&cemdcmd, sizeof(cemdcmd), &transferred);
   412→	if(res != 0 || transferred != sizeof(cemdcmd)) {
   413→		FN_ERROR("upload_cemd_data(): Error: res: %d\ttransferred: %d (expected %d)\n", res, transferred, (int)sizeof(cemdcmd));
   414→		return -1;
   415→	}
   416→	res = get_reply(dev);
   417→	dev->parent->audio_tag++;
   418→	FN_INFO("CEMD data uploaded successfully.\n");
   419→	return 0;
   420→}
